import { ChangeDetectionStrategy, Component, input } from '@angular/core';
import { RouterLink } from '@angular/router';
import { NgIcon, provideIcons } from '@ng-icons/core';
import { lucideBookOpen, lucideBot, lucideChevronRight, lucideSettings2, lucideSquareTerminal } from '@ng-icons/lucide';
import { HlmCollapsibleImports } from '@spartan-ng/helm/collapsible';
import { HlmSidebarImports } from '@spartan-ng/helm/sidebar';

@Component({
	selector: 'spartan-nav-main',
	imports: [HlmSidebarImports, NgIcon, HlmCollapsibleImports, RouterLink],
	providers: [provideIcons({ lucideSquareTerminal, lucideBot, lucideBookOpen, lucideSettings2, lucideChevronRight })],
	changeDetection: ChangeDetectionStrategy.OnPush,
	template: `
		<hlm-sidebar-group>
			<div hlmSidebarGroupLabel>Platform</div>
			<ul hlmSidebarMenu>
				@for (item of items(); track $index) {
					<hlm-collapsible [expanded]="item.isActive ?? false">
						<li hlmSidebarMenuItem>
							<a hlmSidebarMenuButton [routerLink]="item.url">
								<ng-icon [name]="item.icon" />
								{{ item.title }}
							</a>
							@if (item.items; as subItems) {
								<button hlmCollapsibleTrigger hlmSidebarMenuAction class="data-[state=open]:rotate-90">
									<ng-icon name="lucideChevronRight" />
								</button>
								<hlm-collapsible-content>
									<ul hlmSidebarMenuSub>
										@for (subItem of subItems; track $index) {
											<li hlmSidebarMenuSubItem>
												<a hlmSidebarMenuSubButton [routerLink]="subItem.url">{{ subItem.title }}</a>
											</li>
										}
									</ul>
								</hlm-collapsible-content>
							}
						</li>
					</hlm-collapsible>
				}
			</ul>
		</hlm-sidebar-group>
	`,
})
export class NavMain {
	public readonly items = input.required<
		{
			title: string;
			url: string;
			icon: string;
			isActive?: boolean;
			items?: {
				title: string;
				url: string;
			}[];
		}[]
	>();
}

import { ChangeDetectionStrategy, Component, computed, inject, input } from '@angular/core';
import { RouterLink } from '@angular/router';
import { NgIcon, provideIcons } from '@ng-icons/core';
import {
	lucideChartPie,
	lucideEllipsis,
	lucideFolder,
	lucideFrame,
	lucideMap,
	lucideShare,
	lucideTrash2,
} from '@ng-icons/lucide';
import { HlmDropdownMenuImports } from '@spartan-ng/helm/dropdown-menu';
import { HlmSidebarImports, HlmSidebarService } from '@spartan-ng/helm/sidebar';

@Component({
	selector: 'spartan-nav-projects',
	imports: [HlmSidebarImports, NgIcon, RouterLink, HlmDropdownMenuImports],
	providers: [
		provideIcons({ lucideFrame, lucideChartPie, lucideMap, lucideEllipsis, lucideFolder, lucideShare, lucideTrash2 }),
	],
	changeDetection: ChangeDetectionStrategy.OnPush,
	template: `
		<hlm-sidebar-group>
			<div hlmSidebarGroupLabel>Projects</div>
			<ul hlmSidebarMenu>
				@for (project of projects(); track $index) {
					<li hlmSidebarMenuItem>
						<a hlmSidebarMenuButton [routerLink]="project.url">
							<ng-icon [name]="project.icon" />
							{{ project.name }}
						</a>
						<button
							hlmSidebarMenuAction
							showOnHover
							[hlmDropdownMenuTrigger]="menu"
							[hlmDropdownMenuTriggerData]="{ $implicit: { project } }"
							[side]="_menuSide()"
							[align]="_menuAlign()"
						>
							<ng-icon name="lucideEllipsis" />
							<span class="sr-only">More</span>
						</button>
					</li>
				}
				<li hlmSidebarMenuItem>
					<button hlmSidebarMenuButton>
						<ng-icon name="lucideEllipsis" />
						More
					</button>
				</li>
			</ul>
		</hlm-sidebar-group>

		<ng-template #menu let-ctx>
			<hlm-dropdown-menu class="w-48">
				<hlm-dropdown-menu-group>
					<hlm-dropdown-menu-label>{{ ctx.project.name }}</hlm-dropdown-menu-label>
				</hlm-dropdown-menu-group>
				<hlm-dropdown-menu-separator />
				<button hlmDropdownMenuItem>
					<ng-icon name="lucideFolder" />
					View Project
				</button>
				<button hlmDropdownMenuItem>
					<ng-icon name="lucideShare" />
					Share Project
				</button>
				<hlm-dropdown-menu-separator />
				<button hlmDropdownMenuItem>
					<ng-icon name="lucideTrash2" />
					Delete Project
				</button>
			</hlm-dropdown-menu>
		</ng-template>
	`,
})
export class NavProjects {
	private readonly _sidebarService = inject(HlmSidebarService);
	protected readonly _menuSide = computed(() => (this._sidebarService.isMobile() ? 'bottom' : 'right'));
	protected readonly _menuAlign = computed(() => (this._sidebarService.isMobile() ? 'end' : 'start'));

	public readonly projects = input.required<
		{
			name: string;
			url: string;
			icon: string;
		}[]
	>();
}

import { ChangeDetectionStrategy, Component, input } from '@angular/core';
import { RouterLink } from '@angular/router';
import { NgIcon, provideIcons } from '@ng-icons/core';
import { lucideLifeBuoy, lucideSend } from '@ng-icons/lucide';
import { HlmSidebarImports } from '@spartan-ng/helm/sidebar';

@Component({
	selector: 'spartan-nav-secondary',
	imports: [HlmSidebarImports, NgIcon, RouterLink],
	providers: [provideIcons({ lucideLifeBuoy, lucideSend })],
	changeDetection: ChangeDetectionStrategy.OnPush,
	template: `
		<hlm-sidebar-group>
			<div hlmSidebarGroupContent>
				<ul hlmSidebarMenu>
					@for (item of items(); track $index) {
						<li hlmSidebarMenuItem>
							<a hlmSidebarMenuButton size="sm" [routerLink]="item.url">
								<ng-icon [name]="item.icon" />
								{{ item.title }}
							</a>
						</li>
					}
				</ul>
			</div>
		</hlm-sidebar-group>
	`,
})
export class NavSecondary {
	public readonly items = input.required<
		{
			title: string;
			url: string;
			icon: string;
		}[]
	>();
}
